```go
package main

import (
	"io"
	"net/http"
	"net/http/httptest"
	"strings"
	"testing"
)

func TestKV(t *testing.T) {
	srv := httptest.NewServer(newMux(NewStore()))
	defer srv.Close()

	req, _ := http.NewRequest(http.MethodPut, srv.URL+"/kv/a", strings.NewReader("hi"))
	res, err := http.DefaultClient.Do(req)
	if err != nil {
		t.Fatal(err)
	}
	if res.StatusCode != http.StatusCreated {
		t.Fatalf("PUT status = %d, want 201", res.StatusCode)
	}

	res, err = http.Get(srv.URL + "/kv/a")
	if err != nil {
		t.Fatal(err)
	}
	if res.StatusCode != http.StatusOK {
		t.Fatalf("GET status = %d, want 200", res.StatusCode)
	}
	body, _ := io.ReadAll(res.Body)
	if string(body) != "hi" {
		t.Fatalf("GET body = %q, want %q", body, "hi")
	}

	res, _ = http.Get(srv.URL + "/kv/missing")
	if res.StatusCode != http.StatusNotFound {
		t.Fatalf("GET missing status = %d, want 404", res.StatusCode)
	}
}
