# Example task: Write an in-memory store package with sentinel errors ErrNotFound and ErrExists: Create returns ErrExists on a duplicate id, Get and Delete return ErrNotFound when the id is absent, List returns items sorted by id, using a concurrency-safe map.
```go
package store

import (
	"errors"
	"sort"
	"sync"
)

// Sentinel errors returned by the store; callers compare with errors.Is.
var (
	ErrNotFound = errors.New("not found")
	ErrExists   = errors.New("already exists")
)

// Task is the stored entity.
type Task struct {
	ID    string
	Title string
}

// MemStore is a concurrency-safe in-memory implementation of the store.
type MemStore struct {
	mu    sync.RWMutex
	tasks map[string]Task
}

// NewMemStore returns an initialised, empty store.
func NewMemStore() *MemStore {
	return &MemStore{tasks: make(map[string]Task)}
}

// Create inserts t, returning ErrExists if the ID is already present.
func (s *MemStore) Create(t Task) error {
	s.mu.Lock()
	defer s.mu.Unlock()
	if _, ok := s.tasks[t.ID]; ok {
		return ErrExists
	}
	s.tasks[t.ID] = t
	return nil
}

// Get returns the task, or ErrNotFound if absent.
func (s *MemStore) Get(id string) (Task, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	t, ok := s.tasks[id]
	if !ok {
		return Task{}, ErrNotFound
	}
	return t, nil
}

// Delete removes the task, or returns ErrNotFound if absent.
func (s *MemStore) Delete(id string) error {
	s.mu.Lock()
	defer s.mu.Unlock()
	if _, ok := s.tasks[id]; !ok {
		return ErrNotFound
	}
	delete(s.tasks, id)
	return nil
}

// List returns all tasks sorted by ID.
func (s *MemStore) List() []Task {
	s.mu.RLock()
	defer s.mu.RUnlock()
	out := make([]Task, 0, len(s.tasks))
	for _, t := range s.tasks {
		out = append(out, t)
	}
	sort.Slice(out, func(i, j int) bool { return out[i].ID < out[j].ID })
	return out
}
```
# Example task: Write a config package that loads server settings from environment variables with sensible defaults (Addr defaults to :8080, read timeout, max page size), parses durations and integers, validates the result and returns an error for invalid values.
```go
package config

import (
	"fmt"
	"os"
	"strconv"
	"time"
)

// Config holds server settings loaded from the environment with sane defaults.
type Config struct {
	Addr        string
	ReadTimeout time.Duration
	MaxPageSize int
}

func getenv(key, fallback string) string {
	if v := os.Getenv(key); v != "" {
		return v
	}
	return fallback
}

// Load reads configuration from environment variables, applying defaults for
// any that are unset, then validates the result.
func Load() (Config, error) {
	c := Config{
		Addr:        getenv("ADDR", ":8080"),
		ReadTimeout: 5 * time.Second,
		MaxPageSize: 100,
	}
	if s := os.Getenv("READ_TIMEOUT"); s != "" {
		d, err := time.ParseDuration(s)
		if err != nil {
			return Config{}, fmt.Errorf("invalid READ_TIMEOUT: %w", err)
		}
		c.ReadTimeout = d
	}
	if s := os.Getenv("MAX_PAGE_SIZE"); s != "" {
		n, err := strconv.Atoi(s)
		if err != nil {
			return Config{}, fmt.Errorf("invalid MAX_PAGE_SIZE: %w", err)
		}
		c.MaxPageSize = n
	}
	if err := c.Validate(); err != nil {
		return Config{}, err
	}
	return c, nil
}

// Validate reports whether the configuration is usable.
func (c Config) Validate() error {
	if c.Addr == "" {
		return fmt.Errorf("addr must not be empty")
	}
	if c.MaxPageSize <= 0 {
		return fmt.Errorf("max page size must be positive, got %d", c.MaxPageSize)
	}
	return nil
}
```

