# Example task: Write a models package (domain types only, standard library only) defining MULTIPLE exported domain types in ONE file with JSON tags: an entity struct (ID, Title/Name, Status string; valid status from a fixed set) AND a separate Event struct {Type, TaskID string} for the event seam, plus an exported sentinel var ErrInvalid = errors.New and a (t Entity) Validate() error method wrapping ErrInvalid via fmt.Errorf on empty or invalid fields. EVERY type the file's spec names must exist here — other packages import and reference them (never omit the Event type).
```go
package models

import (
	"errors"
	"fmt"
)

// ErrInvalid is the sentinel wrapped by every validation failure.
var ErrInvalid = errors.New("invalid")

// Order is a domain entity with a lifecycle status.
type Order struct {
	ID     string `json:"id"`
	Status string `json:"status"`
}

// Event is a SEPARATE domain type in the SAME package — a package often holds
// more than one type; define EVERY type the spec lists, not just the first.
type Event struct {
	Type    string `json:"type"`
	OrderID string `json:"order_id"`
}

// Validate reports whether the order is well-formed, wrapping ErrInvalid.
func (o Order) Validate() error {
	if o.ID == "" {
		return fmt.Errorf("%w: id is required", ErrInvalid)
	}
	if o.Status != "open" && o.Status != "shipped" && o.Status != "closed" {
		return fmt.Errorf("%w: bad status %q", ErrInvalid, o.Status)
	}
	return nil
}
```
# Example task: Write the canonical layered-backend service package (standard library only): TaskService depending on BOTH a Store interface and an EventEnqueuer seam, constructed with NewTaskService(store, enqueuer) — constructors take every dependency explicitly. Create validates (ErrInvalid via errors.Is on bad status/missing fields), stores (ErrExists passthrough on duplicate ID), and enqueues one task.created event ONLY after success. List(limit int) returns at most limit tasks sorted by ID, limit <= 0 returns all. Unique IDs via strconv.Itoa.
```go
// Package main is the canonical layered-backend service: a TaskService that
// depends on BOTH a Store and an outbound EventEnqueuer seam — constructors in
// real backends take every dependency explicitly: NewTaskService(store, enq).
package main

import (
	"errors"
	"sort"
	"strconv"
	"sync"
)

var (
	ErrInvalid  = errors.New("invalid task")
	ErrExists   = errors.New("already exists")
	ErrNotFound = errors.New("not found")
)

type Task struct {
	ID     string
	Title  string
	Status string
}

type Event struct {
	Type   string
	TaskID string
}

// EventEnqueuer is the service's outbound seam; a worker satisfies it in
// production, a slice-backed fake records calls in tests.
type EventEnqueuer interface {
	Enqueue(e Event)
}

type Store interface {
	Create(t Task) error
	List() []Task
}

type MemStore struct {
	mu    sync.RWMutex
	items map[string]Task
}

func NewMemStore() *MemStore { return &MemStore{items: make(map[string]Task)} }

func (s *MemStore) Create(t Task) error {
	s.mu.Lock()
	defer s.mu.Unlock()
	if _, dup := s.items[t.ID]; dup {
		return ErrExists
	}
	s.items[t.ID] = t
	return nil
}

func (s *MemStore) List() []Task {
	s.mu.RLock()
	defer s.mu.RUnlock()
	out := make([]Task, 0, len(s.items))
	for _, t := range s.items {
		out = append(out, t)
	}
	sort.Slice(out, func(i, j int) bool { return out[i].ID < out[j].ID })
	return out
}

