# Example task: Write a package main users REST backend (standard library only) in one file: a User{ID,Name,Email} type; a Store interface + goroutine-safe in-memory MemStore (RWMutex, NewMemStore) with Create (ErrExists on dup id), Get/Delete (ErrNotFound), List (id-sorted); logging+recover middleware with a Chain helper; JSON handlers returning correct REST codes (201/409/200/404/204, 400 on malformed body); and NewRouter(Store) wiring an http.ServeMux with POST/GET /users, GET/DELETE /users/{id} via r.PathValue, wrapped in the middleware.
```go
package main

import (
	"encoding/json"
	"errors"
	"log"
	"net/http"
	"sort"
	"sync"
	"time"
)

// --- from store.go ---
// ErrNotFound is returned when a lookup key is absent. Callers match it with
// errors.Is so the sentinel can be wrapped with context higher up.
var ErrNotFound = errors.New("not found")

// User is the stored entity.
type User struct {
	ID    string
	Name  string
	Email string
}

// Store is the abstraction the rest of the app depends on. A Postgres or SQLite
// implementation can be dropped in without touching callers.
type Store interface {
	Create(u User) error
	Get(id string) (User, error)
	List() []User
	Delete(id string) error
}

// ErrExists is returned by Create when the ID is already taken.
var ErrExists = errors.New("already exists")

// MemStore is a goroutine-safe in-memory Store.
type MemStore struct {
	mu    sync.RWMutex
	users map[string]User
}

// NewMemStore returns a ready-to-use empty store.
func NewMemStore() *MemStore {
	return &MemStore{users: make(map[string]User)}
}

func (s *MemStore) Create(u User) error {
	s.mu.Lock()
	defer s.mu.Unlock()
	if _, ok := s.users[u.ID]; ok {
		return ErrExists
	}
	s.users[u.ID] = u
	return nil
}

func (s *MemStore) Get(id string) (User, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	u, ok := s.users[id]
	if !ok {
		return User{}, ErrNotFound
	}
	return u, nil
}

// List returns every user ordered by ID so results are deterministic.
func (s *MemStore) List() []User {
	s.mu.RLock()
	defer s.mu.RUnlock()
	out := make([]User, 0, len(s.users))
	for _, u := range s.users {
		out = append(out, u)
	}
	sort.Slice(out, func(i, j int) bool { return out[i].ID < out[j].ID })
	return out
}

func (s *MemStore) Delete(id string) error {
	s.mu.Lock()
	defer s.mu.Unlock()
	if _, ok := s.users[id]; !ok {
		return ErrNotFound
	}
	delete(s.users, id)
	return nil
}

// compile-time proof MemStore satisfies Store.
var _ Store = (*MemStore)(nil)

// --- from middleware.go ---
// Middleware wraps an http.Handler to add one cross-cutting concern.
// Composing them keeps handlers focused on business logic.
type Middleware func(http.Handler) http.Handler

// Chain applies middlewares so the FIRST listed is the OUTERMOST layer:
// Chain(h, Logging, Recover) runs Logging(Recover(h)).
func Chain(h http.Handler, mws ...Middleware) http.Handler {
	for i := len(mws) - 1; i >= 0; i-- {
		h = mws[i](h)
	}
	return h
}

// statusRecorder captures the status code a downstream handler writes so the
// logging middleware can report it. It defaults to 200 like net/http does.
type statusRecorder struct {
	http.ResponseWriter
	status int
}

func (r *statusRecorder) WriteHeader(code int) {
	r.status = code
	r.ResponseWriter.WriteHeader(code)
}

// Logging records method, path, resolved status and latency for each request.
func Logging(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		start := time.Now()
		rec := &statusRecorder{ResponseWriter: w, status: http.StatusOK}
		next.ServeHTTP(rec, r)
		log.Printf("%s %s -> %d (%s)", r.Method, r.URL.Path, rec.status, time.Since(start))
	})
}

// Recover converts a panic in any downstream handler into a 500 response
// instead of letting it crash the server.
func Recover(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		defer func() {
			if err := recover(); err != nil {
				log.Printf("panic: %v", err)
				http.Error(w, "internal server error", http.StatusInternalServerError)
			}
		}()
		next.ServeHTTP(w, r)
	})
}

