// Task represents a task with a title, status, and project ID.
type Task struct {
	ID        string `json:"id"`
	Title     string `json:"title"`
	Status    string `json:"status"`
	ProjectID string `json:"project_id"`
}

// Project represents a project with a name.
type Project struct {
	ID   string `json:"id"`
	Name string `json:"name"`
}

// Validate checks if the Task is valid.
func (t Task) Validate() error {
	if t.Title == "" {
		return fmt.Errorf("%w: title is required", ErrValidation)
	}
	if t.Status != "todo" && t.Status != "doing" && t.Status != "done" {
		return fmt.Errorf("%w: bad status %q", ErrValidation, t.Status)
	}
	return nil
}

// Validate checks if the Project is valid.
func (p Project) Validate() error {
	if p.Name == "" {
		return fmt.Errorf("%w: name is required", ErrValidation)
	}
	return nil
}

