package main

import (
	"log"
	"net/http"
	"time"
)

// Middleware wraps an http.Handler to add one cross-cutting concern.
// Composing them keeps handlers focused on business logic.
type Middleware func(http.Handler) http.Handler

// Chain applies middlewares so the FIRST listed is the OUTERMOST layer:
// Chain(h, Logging, Recover) runs Logging(Recover(h)).
func Chain(h http.Handler, mws ...Middleware) http.Handler {
	for i := len(mws) - 1; i >= 0; i-- {
		h = mws[i](h)
	}
	return h
}

// statusRecorder captures the status code a downstream handler writes so the
// logging middleware can report it. It defaults to 200 like net/http does.
type statusRecorder struct {
	http.ResponseWriter
	status int
}

func (r *statusRecorder) WriteHeader(code int) {
	r.status = code
	r.ResponseWriter.WriteHeader(code)
}

// Logging records method, path, resolved status and latency for each request.
func Logging(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		start := time.Now()
		rec := &statusRecorder{ResponseWriter: w, status: http.StatusOK}
		next.ServeHTTP(rec, r)
		log.Printf("%s %s -> %d (%s)", r.Method, r.URL.Path, rec.status, time.Since(start))
	})
}

// Recover converts a panic in any downstream handler into a 500 response
// instead of letting it crash the server.
func Recover(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		defer func() {
			if err := recover(); err != nil {
				log.Printf("panic: %v", err)
				http.Error(w, "internal server error", http.StatusInternalServerError)
			}
		}()
		next.ServeHTTP(w, r)
	})
}

--- handlers.go ---
package main

import (
	"encoding/json"
	"errors"
	"net/http"
)

// UserHandler handles HTTP requests for the /users resource.
type UserHandler struct {
	store Store
}

// NewUserHandler creates a new UserHandler with the given Store.
func NewUserHandler(store Store) *UserHandler {
	return &UserHandler{store: store}
}

// Create decodes a JSON User from the request body and stores it.
func (h *UserHandler) Create(w http.ResponseWriter, r *http.Request) {
	var u User
	if err := json.NewDecoder(r.Body).Decode(&u); err != nil {
		writeJSON(w, http.StatusBadRequest, nil)
		return
	}
	if err := h.store.Create(u); err != nil {
		if errors.Is(err, ErrExists) {
			writeJSON(w, http.StatusConflict, nil)
		} else {
			writeJSON(w, http.StatusInternalServerError, nil)
		}
		return
	}
	writeJSON(w, http.StatusCreated, u)
}

// Get reads the {id} path value and returns the user as JSON.
func (h *UserHandler) Get(w http.ResponseWriter, r *http.Request) {
	id := r.PathValue("id")
	u, err := h.store.Get(id)
	if err != nil {
		if errors.Is(err, ErrNotFound) {
			writeJSON(w, http.StatusNotFound, nil)
		} else {
			writeJSON(w, http.StatusInternalServerError, nil)
		}
		return
	}
	writeJSON(w, http.StatusOK, u)
}

// List returns all users as a JSON array.
func (h *UserHandler) List(w http.ResponseWriter, r *http.Request) {
	users := h.store.List()
	writeJSON(w, http.StatusOK, users)
}

// Delete removes {id} returning 204, or 404 if absent.
func (h *UserHandler) Delete(w http.ResponseWriter, r *http.Request) {
	id := r.PathValue("id")
	if err := h.store.Delete(id); err != nil {
		if errors.Is(err, ErrNotFound) {
			writeJSON(w, http.StatusNotFound, nil)
		} else {
			writeJSON(w, http.StatusInternalServerError, nil)
		}
		return
	}
	writeJSON(w, http.StatusNoContent, nil)
}

// writeJSON writes the given value as JSON to the response writer with the given status code.
func writeJSON(w http.ResponseWriter, status int, v interface{}) {
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(status)
	if v != nil {
		json.NewEncoder(w).Encode(v)
	}
}

--- router.go ---
package main

import (
	"net/http"
)

// NewRouter builds an http.ServeMux mapping method+pattern routes to a UserHandler.
func NewRouter(s Store) http.Handler {
	mux := http.NewServeMux()
	userHandler := NewUserHandler(s)

	mux.HandleFunc("POST /users", userHandler.Create)
	mux.HandleFunc("GET /users", userHandler.List)
	mux.HandleFunc("GET /users/{id}", userHandler.Get)
	mux.HandleFunc("DELETE /users/{id}", userHandler.Delete)
	mux.HandleFunc("GET /health", func(w http.ResponseWriter, r *http.Request) {
		_, _ = w.Write([]byte("ok"))
	})

	return Chain(mux, Logging, Recover)
}

--- main.go ---
package main

import (
	"context"
	"log"
	"net/http"
	"os"
	"os/signal"
	"syscall"
	"time"
)

func main() {
	store := NewMemStore()
	router := NewRouter(store)

	srv := &http.Server{Addr: ":8080", Handler: router}

	go func() {
		if err := srv.ListenAndServe(); err != nil && err != http.ErrServerClosed {
			log.Fatalf("listen: %s\n", err)
		}
	}()

	quit := make(chan os.Signal, 1)
	signal.Notify(quit, syscall.SIGINT, syscall.SIGTERM)

	<-quit
	log.Println("Shutting down server...")

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	if err := srv.Shutdown(ctx); err != nil {
		log.Fatalf("shutdown: %s\n", err)
	}

	log.Println("Server exiting")
}


