package main

import (
	"errors"
	"sync"
	"testing"
)

func TestCreateGetListDelete(t *testing.T) {
	s := NewMemStore()
	if err := s.Create(User{ID: "2", Name: "Tim"}); err != nil {
		t.Fatal(err)
	}
	if err := s.Create(User{ID: "1", Name: "Ada"}); err != nil {
		t.Fatal(err)
	}

	// duplicate ID -> ErrExists
	if err := s.Create(User{ID: "1", Name: "Dup"}); !errors.Is(err, ErrExists) {
		t.Fatalf("want ErrExists, got %v", err)
	}

	u, err := s.Get("1")
	if err != nil || u.Name != "Ada" {
		t.Fatalf("get: %v %+v", err, u)
	}

	// List is ID-ordered and deterministic.
	list := s.List()
	if len(list) != 2 || list[0].ID != "1" || list[1].ID != "2" {
		t.Fatalf("list order wrong: %+v", list)
	}

	if err := s.Delete("1"); err != nil {
		t.Fatal(err)
	}
	if _, err := s.Get("1"); !errors.Is(err, ErrNotFound) {
		t.Fatalf("want ErrNotFound after delete, got %v", err)
	}
	if err := s.Delete("nope"); !errors.Is(err, ErrNotFound) {
		t.Fatalf("delete missing: want ErrNotFound, got %v", err)
	}
}

// The RWMutex must make concurrent use race-free (run with -race).
func TestConcurrentAccess(t *testing.T) {
	s := NewMemStore()
	var wg sync.WaitGroup
	for i := 0; i < 50; i++ {
		wg.Add(1)
		go func(i int) {
			defer wg.Done()
			id := string(rune('A' + i%26))
			_ = s.Create(User{ID: id, Name: id})
			_, _ = s.Get(id)
			_ = s.List()
		}(i)
	}
	wg.Wait()
}
