package main

import (
	"crypto/subtle"
	"net/http"
)

// Auth returns middleware enforcing `Authorization: Bearer <token>` on every
// request. Constructed once with the expected token, it WRAPS the next
// handler — callers compose it as Auth(token)(mux), they never invoke the
// middleware with (w, r) directly:
//
//	protected := Auth("secret")(mux)
func Auth(token string) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			got, ok := bearerToken(r)
			if !ok || subtle.ConstantTimeCompare([]byte(got), []byte(token)) != 1 {
				http.Error(w, "unauthorized", http.StatusUnauthorized)
				return
			}
			next.ServeHTTP(w, r)
		})
	}
}

func bearerToken(r *http.Request) (string, bool) {
	const prefix = "Bearer "
	h := r.Header.Get("Authorization")
	if len(h) <= len(prefix) || h[:len(prefix)] != prefix {
		return "", false
	}
	return h[len(prefix):], true
}

func main() {
	mux := http.NewServeMux()
	mux.HandleFunc("GET /health", func(w http.ResponseWriter, r *http.Request) {
		w.WriteHeader(http.StatusOK)
	})
	_ = Auth("secret")(mux) // wire into an http.Server in a real backend
}
```
# Example task: Write a package main HTTP handler that wires an http.ServeMux (standard library only, no third-party router) for GET /kv/{key} and PUT /kv/{key} backed by an in-memory store. Use the Go 1.22+ method+wildcard route patterns and r.PathValue. PUT returns 201 Created, GET returns the value (200) or 404 if absent. Expose newMux(s *Store) *http.ServeMux.
```go
package main

import (
	"io"
	"net/http"
	"sync"
)

type Store struct {
	mu sync.RWMutex
	m  map[string]string
}

func NewStore() *Store { return &Store{m: make(map[string]string)} }

func (s *Store) Get(key string) (string, bool) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	v, ok := s.m[key]
	return v, ok
}

func (s *Store) Set(key, value string) {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.m[key] = value
}

// newMux wires routes with the Go 1.22+ method+wildcard ServeMux patterns —
// no third-party router. r.PathValue extracts the {key} segment.
func newMux(s *Store) *http.ServeMux {
	mux := http.NewServeMux()
	mux.HandleFunc("GET /kv/{key}", func(w http.ResponseWriter, r *http.Request) {
		v, ok := s.Get(r.PathValue("key"))
		if !ok {
			http.Error(w, "not found", http.StatusNotFound)
			return
		}
		w.Header().Set("Content-Type", "text/plain")
		io.WriteString(w, v)
	})
	mux.HandleFunc("PUT /kv/{key}", func(w http.ResponseWriter, r *http.Request) {
		body, err := io.ReadAll(r.Body)
		if err != nil {
			http.Error(w, "bad body", http.StatusBadRequest)
			return
		}
		s.Set(r.PathValue("key"), string(body))
		w.WriteHeader(http.StatusCreated)
	})
	return mux
}

func main() {
	http.ListenAndServe(":8080", newMux(NewStore()))
}
```

