package main

import (
	"bytes"
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"testing"
)

// fresh router+store per call = isolated cases (what the model's test failed to do)
func newAPI() http.Handler { return NewRouter(NewMemStore()) }

func do(t *testing.T, h http.Handler, method, path, body string) *httptest.ResponseRecorder {
	t.Helper()
	var r *http.Request
	if body != "" {
		r = httptest.NewRequest(method, path, bytes.NewBufferString(body))
		r.Header.Set("Content-Type", "application/json")
	} else {
		r = httptest.NewRequest(method, path, nil)
	}
	w := httptest.NewRecorder()
	h.ServeHTTP(w, r)
	return w
}

func TestCreateReturns201AndEcho(t *testing.T) {
	h := newAPI()
	w := do(t, h, "POST", "/users", `{"ID":"1","Name":"Ada","Email":"a@x.io"}`)
	if w.Code != http.StatusCreated {
		t.Fatalf("create: want 201, got %d (%s)", w.Code, w.Body)
	}
	var u User
	json.Unmarshal(w.Body.Bytes(), &u)
	if u.ID != "1" || u.Name != "Ada" {
		t.Fatalf("echo wrong: %+v", u)
	}
}
func TestDuplicateReturns409(t *testing.T) {
	h := newAPI()
	do(t, h, "POST", "/users", `{"ID":"1","Name":"Ada"}`)
	w := do(t, h, "POST", "/users", `{"ID":"1","Name":"Dup"}`)
	if w.Code != http.StatusConflict {
		t.Fatalf("dup: want 409, got %d", w.Code)
	}
}
func TestGetMissingReturns404(t *testing.T) {
	h := newAPI()
	w := do(t, h, "GET", "/users/nope", "")
	if w.Code != http.StatusNotFound {
		t.Fatalf("get missing: want 404, got %d", w.Code)
	}
}
func TestGetExistingReturns200(t *testing.T) {
	h := newAPI()
	do(t, h, "POST", "/users", `{"ID":"7","Name":"Tim"}`)
	w := do(t, h, "GET", "/users/7", "")
	if w.Code != http.StatusOK {
		t.Fatalf("get: want 200, got %d", w.Code)
	}
}
func TestDeleteExistingThen404(t *testing.T) {
	h := newAPI()
	do(t, h, "POST", "/users", `{"ID":"9","Name":"Zoe"}`)
	if w := do(t, h, "DELETE", "/users/9", ""); w.Code != http.StatusNoContent {
		t.Fatalf("delete: want 204, got %d", w.Code)
	}
	if w := do(t, h, "GET", "/users/9", ""); w.Code != http.StatusNotFound {
		t.Fatalf("get after delete: want 404, got %d", w.Code)
	}
}
func TestDeleteMissingReturns404(t *testing.T) {
	h := newAPI()
	if w := do(t, h, "DELETE", "/users/absent", ""); w.Code != http.StatusNotFound {
		t.Fatalf("delete missing: want 404, got %d", w.Code)
	}
}
func TestListReturnsAll(t *testing.T) {
	h := newAPI()
	do(t, h, "POST", "/users", `{"ID":"1","Name":"A"}`)
	do(t, h, "POST", "/users", `{"ID":"2","Name":"B"}`)
	w := do(t, h, "GET", "/users", "")
	if w.Code != http.StatusOK {
		t.Fatalf("list: want 200, got %d", w.Code)
	}
	var us []User
	json.Unmarshal(w.Body.Bytes(), &us)
	if len(us) != 2 {
		t.Fatalf("list len: want 2, got %d", len(us))
	}
}
func TestMalformedJSONReturns400(t *testing.T) {
	h := newAPI()
	w := do(t, h, "POST", "/users", `{"ID":"1",`)
	if w.Code != http.StatusBadRequest {
		t.Fatalf("malformed: want 400, got %d", w.Code)
	}
}
